import React, { useState, useEffect, useCallback } from 'react';
import { fetchRDVData, fetchRemunerations } from './sheets';

const LOGO = "data:image/jpeg;base64,";

const COACH_COLORS = {
  Alexis: '#2E8BE6', Gautier: '#1D9E75', Mathilde: '#E8417E',
  Jenny: '#BA7517', Rémi: '#7F77DD',
};
const COACHES = ['Alexis', 'Rémi', 'Mathilde', 'Jenny', 'Gautier'];
const OBJ = { rdv: 20, ca: 30000 };
const PERIODES = [
  { value: 'mois', label: 'Ce mois' },
  { value: 'ytd',  label: 'YTD' },
  { value: 't2',   label: 'T2' },
  { value: 't1',   label: 'T1' },
];

// ─── Commission estimée ───────────────────────────────────────────────────────
function calcCommission(coach, d) {
  if (!d) return null;
  if (coach === 'Rémi')     return Math.round(d.ca * 0.10);
  if (coach === 'Mathilde') return Math.round(d.ca * 0.20);
  if (coach === 'Jenny')    return Math.round(d.ca * 0.20);
  if (coach === 'Alexis')   return Math.round(d.prescripteurCA * 0.05);
  return null; // Gautier
}

// ─── Utils ───────────────────────────────────────────────────────────────────
const fmt  = n => (n || 0).toLocaleString('fr-FR');
const fmtK = n => n >= 1000 ? `${(n/1000).toFixed(1)}k€` : `${n || 0}€`;
const pct  = (a, b) => b > 0 ? Math.round(a / b * 100) : 0;

function Delta({ cur, prev, isEuro }) {
  if (prev == null || prev === 0 && cur === 0) return null;
  const diff = cur - prev;
  if (diff === 0) return <span style={{ fontSize: 10, color: '#7da3c8' }}>= préc.</span>;
  const up = diff > 0;
  const abs = Math.abs(diff);
  const label = isEuro ? fmtK(abs) : abs;
  return <span style={{ fontSize: 10, color: up ? '#1D9E75' : '#e24b4a' }}>{up ? '▲' : '▼'} {label}</span>;
}

function Pill({ children, color, bg }) {
  return <span style={{ fontSize: 10, padding: '2px 8px', borderRadius: 10, fontWeight: 700, background: bg, color, display: 'inline-block' }}>{children}</span>;
}

function Bar({ value, max, color = '#2E8BE6' }) {
  const w = Math.min(100, pct(value, max));
  return (
    <div style={{ background: '#dbeafe', borderRadius: 4, height: 6, overflow: 'hidden', marginTop: 4 }}>
      <div style={{ height: 6, borderRadius: 4, background: color, width: `${w}%`, transition: 'width .4s' }} />
    </div>
  );
}

function Gauge({ label, value, max, color, unit = '' }) {
  const p = Math.min(100, pct(value, max));
  return (
    <div style={{ background: '#fff', border: '0.5px solid #c7d9f5', borderRadius: 12, padding: '1rem' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 6 }}>
        <span style={{ fontSize: 12, color: '#4b6fa8', fontWeight: 500 }}>{label}</span>
        <span style={{ fontSize: 18, fontWeight: 700, color }}>{value}{unit}</span>
      </div>
      <div style={{ background: '#dbeafe', borderRadius: 6, height: 8, overflow: 'hidden' }}>
        <div style={{ height: 8, borderRadius: 6, background: color, width: `${p}%`, transition: 'width .5s' }} />
      </div>
      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 4, fontSize: 11, color: '#7da3c8' }}>
        <span>{p}%</span><span>obj. {max}{unit}</span>
      </div>
    </div>
  );
}

// ─── Tableau générique ────────────────────────────────────────────────────────
function Table({ headers, rows, emptyMsg = 'Aucune donnée' }) {
  if (!rows.length) return <div style={{ color: '#7da3c8', fontSize: 12, padding: '1rem 0' }}>{emptyMsg}</div>;
  return (
    <div style={{ overflowX: 'auto' }}>
      <table style={{ width: '100%', fontSize: 12, borderCollapse: 'collapse' }}>
        <thead>
          <tr style={{ borderBottom: '0.5px solid #c7d9f5' }}>
            {headers.map(h => (
              <th key={h} style={{ textAlign: 'left', padding: '5px 8px', fontWeight: 500, color: '#7da3c8', whiteSpace: 'nowrap' }}>{h}</th>
            ))}
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i} style={{ borderBottom: '0.5px solid #e8f1fb' }}>
              {r.map((cell, j) => (
                <td key={j} style={{ padding: '8px', whiteSpace: 'nowrap', color: '#0f1f3d' }}>{cell}</td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ─── APP ──────────────────────────────────────────────────────────────────────
export default function App() {
  const [data, setData]         = useState(null);
  const [loading, setLoading]   = useState(true);
  const [lastUpdate, setLastUpdate] = useState('Chargement...');
  const [coach, setCoach]       = useState('tous');
  const [periode, setPeriode]   = useState('mois');

  const load = useCallback(async () => {
    try {
      const rdv = await fetchRDVData(periode);
      if (rdv) setData(rdv);
      setLastUpdate(new Date().toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }));
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  }, [periode]);

  useEffect(() => { setLoading(true); load(); }, [periode]);
  useEffect(() => { const iv = setInterval(load, 5 * 60 * 1000); return () => clearInterval(iv); }, [load]);

  // ── Stats selon filtre coach ──
  const src     = coach === 'tous' ? data?.tous     : data?.[coach];
  const prevSrc = coach === 'tous' ? data?._precMois?.tous : data?._precMois?.[coach];
  const d  = src  || {};
  const p  = prevSrc || {};

  const txConv     = (d.gagnes + d.perdus) > 0 ? pct(d.gagnes, d.gagnes + d.perdus) : 0;
  const prevTxConv = (p.gagnes + p.perdus) > 0 ? pct(p.gagnes, p.gagnes + p.perdus) : 0;
  const panier     = d.gagnes > 0 ? Math.round(d.ca / d.gagnes) : 0;
  const prevPanier = p.gagnes > 0 ? Math.round(p.ca / p.gagnes) : 0;

  // Commission estimée
  const commission = coach !== 'tous' ? calcCommission(coach, d) : null;

  // Filtres tableaux
  const dealsGagnes  = (data?._dealsGagnes  || []).filter(r => coach === 'tous' || r.coach === coach);
  const dealsEnCours = (data?._dealsEnCours || []).filter(r => coach === 'tous' || r.coach === coach);
  const origines     = data?._origines || {};
  const originesRows = Object.entries(origines)
    .sort((a, b) => b[1].rdv - a[1].rdv)
    .map(([orig, v]) => [
      orig,
      <span style={{ fontWeight: 600, color: '#2E8BE6' }}>{v.rdv}</span>,
      <span style={{ fontWeight: 600, color: '#1D9E75' }}>{v.ca > 0 ? fmtK(v.ca) : '—'}</span>,
    ]);

  // Commissions toutes équipe
  const commissionRows = COACHES.map(c => {
    const cd = data?.[c] || {};
    const com = calcCommission(c, cd);
    return [
      <span style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
        <span style={{ width: 8, height: 8, borderRadius: '50%', background: COACH_COLORS[c], display: 'inline-block' }} />
        {c}
      </span>,
      fmtK(cd.ca || 0),
      com != null ? <span style={{ fontWeight: 700, color: '#1D9E75' }}>{fmtK(com)}</span> : <span style={{ color: '#7da3c8' }}>—</span>,
    ];
  });

  return (
    <div style={{ background: '#eef4fd', minHeight: '100vh', padding: '1rem',
      fontFamily: "'system-ui', '-apple-system', sans-serif", color: '#0f1f3d' }}>
      <div style={{ maxWidth: 960, margin: '0 auto' }}>

        {/* ── Header ── */}
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.25rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <img src={LOGO} alt="Kwala" style={{ width: 36, height: 36, objectFit: 'contain', borderRadius: 6, background: '#0f1f3d', padding: 4 }} />
            <div>
              <div style={{ fontSize: 20, fontWeight: 800, color: '#0f1f3d', letterSpacing: -0.5 }}>Kwala Dashboard</div>
              <div style={{ fontSize: 11, color: '#7da3c8' }}>Mis à jour {lastUpdate}</div>
            </div>
          </div>
          <Pill color='#1e40af' bg='#dbeafe'>T2 2026</Pill>
        </div>

        {/* ── Filtres ── */}
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, marginBottom: '1rem' }}>
          {/* Coach */}
          <div style={{ display: 'flex', gap: 3, background: '#c7d9f5', borderRadius: 8, padding: 3 }}>
            {[{ k: 'tous', l: 'Tous' }, ...COACHES.map(c => ({ k: c, l: c }))].map(({ k, l }) => {
              const active = coach === k;
              const col = k === 'tous' ? '#2E8BE6' : COACH_COLORS[k];
              return (
                <button key={k} onClick={() => setCoach(k)} style={{
                  padding: '5px 11px', borderRadius: 6, border: 'none', fontSize: 12, fontWeight: 500,
                  cursor: 'pointer', background: active ? col : 'transparent', color: active ? '#fff' : '#2E5FA3',
                }}>{l}</button>
              );
            })}
          </div>
          {/* Période */}
          <div style={{ display: 'flex', gap: 3, background: '#c7d9f5', borderRadius: 8, padding: 3 }}>
            {PERIODES.map(({ value, label }) => (
              <button key={value} onClick={() => setPeriode(value)} style={{
                padding: '5px 11px', borderRadius: 6, border: 'none', fontSize: 12, fontWeight: 500,
                cursor: 'pointer', background: periode === value ? '#2E8BE6' : 'transparent',
                color: periode === value ? '#fff' : '#2E5FA3',
              }}>{label}</button>
            ))}
          </div>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '3rem', color: '#4b6fa8' }}>Chargement...</div>
        ) : (<>

        {/* ── Métriques ── */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(130px, 1fr))', gap: 8, marginBottom: '1rem' }}>
          {[
            { label: 'RDV réalisés',  val: d.rdv || 0,      prev: p.rdv,     disp: d.rdv || 0,      isEuro: false },
            { label: 'Deals gagnés',  val: d.gagnes || 0,   prev: p.gagnes,  disp: d.gagnes || 0,   isEuro: false, color: '#1D9E75' },
            { label: 'CA signé',      val: fmtK(d.ca || 0), prev: p.ca,      disp: d.ca || 0,       isEuro: true,  color: '#2E8BE6' },
            { label: 'Taux conv.',    val: `${txConv}%`,    prev: prevTxConv,disp: txConv,           isEuro: false },
            { label: 'Panier moyen',  val: panier > 0 ? fmtK(panier) : '—', prev: prevPanier, disp: panier, isEuro: true },
            { label: 'Pipe estimé',   val: fmtK(d.caEncours || 0), prev: null, disp: 0, isEuro: true, color: '#7F77DD' },
          ].map(({ label, val, prev, disp, isEuro, color }) => (
            <div key={label} style={{ background: '#fff', border: '0.5px solid #c7d9f5', borderRadius: 10, padding: '0.75rem' }}>
              <div style={{ fontSize: 11, color: '#4b6fa8', marginBottom: 3 }}>{label}</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: color || '#0f1f3d' }}>{val}</div>
              {typeof prev === 'number' && <Delta cur={disp} prev={prev} isEuro={isEuro} />}
            </div>
          ))}
          {commission != null && (
            <div style={{ background: '#d1fae5', border: '0.5px solid #6ee7b7', borderRadius: 10, padding: '0.75rem' }}>
              <div style={{ fontSize: 11, color: '#065f46', marginBottom: 3 }}>Commission est. {coach}</div>
              <div style={{ fontSize: 18, fontWeight: 700, color: '#065f46' }}>{fmtK(commission)}</div>
            </div>
          )}
        </div>

        {/* ── Jauges ── */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: '1rem' }}>
          <Gauge label="RDV équipe" value={data?.tous?.rdv || 0} max={OBJ.rdv} color='#2E8BE6' />
          <Gauge label="CA signé équipe" value={Math.round((data?.tous?.ca || 0) / 1000)} max={30} color='#1D9E75' unit='k€' />
        </div>

        {/* ── Ligne : Deals signés + Origines ── */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: '1rem' }}>

          {/* Deals signés */}
          <div style={{ background: '#fff', border: '0.5px solid #c7d9f5', borderRadius: 14, padding: '1rem' }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: '#4b6fa8', marginBottom: 10, textTransform: 'uppercase', letterSpacing: .5 }}>
              Derniers deals signés
            </div>
            <Table
              headers={['Contact', 'Entreprise', 'Coach', 'CA', 'Offre']}
              emptyMsg="Aucun deal sur cette période"
              rows={dealsGagnes.slice(0, 8).map(d => [
                <span style={{ color: '#4b6fa8' }}>{d.contact || '—'}</span>,
                <span style={{ fontWeight: 600 }}>{d.entreprise || '—'}</span>,
                <span style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                  <span style={{ width: 7, height: 7, borderRadius: '50%', background: COACH_COLORS[d.coach] || '#888', display: 'inline-block' }} />
                  {d.coach}
                </span>,
                <span style={{ fontWeight: 700, color: '#1D9E75' }}>{fmtK(d.ca)}</span>,
                d.offre ? <Pill color='#1e40af' bg='#dbeafe'>{d.offre}</Pill> : '—',
              ])}
            />
          </div>

          {/* Origines (sans filtre) */}
          <div style={{ background: '#fff', border: '0.5px solid #c7d9f5', borderRadius: 14, padding: '1rem' }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: '#4b6fa8', marginBottom: 10, textTransform: 'uppercase', letterSpacing: .5 }}>
              Origine des RDV
            </div>
            <Table headers={['Origine', 'RDV réalisés', 'CA généré']} rows={originesRows} emptyMsg="Aucune donnée" />
          </div>
        </div>

        {/* ── Commissions équipe (si "tous") ── */}
        {coach === 'tous' && (
          <div style={{ background: '#fff', border: '0.5px solid #c7d9f5', borderRadius: 14, padding: '1rem', marginBottom: '1rem' }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: '#4b6fa8', marginBottom: 10, textTransform: 'uppercase', letterSpacing: .5 }}>
              Commissions estimées
            </div>
            <Table headers={['Coach', 'CA signé', 'Commission est.']} rows={commissionRows} />
          </div>
        )}

        {/* ── Deals en cours ── */}
        {dealsEnCours.length > 0 && (
          <div style={{ background: '#fff', border: '0.5px solid #c7d9f5', borderRadius: 14, padding: '1rem', marginBottom: '1rem' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 }}>
              <div style={{ fontSize: 12, fontWeight: 700, color: '#4b6fa8', textTransform: 'uppercase', letterSpacing: .5 }}>
                Deals en cours
              </div>
              <span style={{ fontSize: 12, fontWeight: 700, color: '#7F77DD' }}>
                Pipe : {fmtK(dealsEnCours.reduce((s, r) => s + (r.caEst || 0), 0))}
              </span>
            </div>
            <Table
              headers={['Contact', 'Entreprise', 'Coach', 'Date RDV', 'Offre', 'CA est.']}
              rows={dealsEnCours.map(d => [
                <span style={{ color: '#4b6fa8' }}>{d.contact || '—'}</span>,
                <span style={{ fontWeight: 600 }}>{d.entreprise || '—'}</span>,
                <span style={{ display: 'flex', alignItems: 'center', gap: 5 }}>
                  <span style={{ width: 7, height: 7, borderRadius: '50%', background: COACH_COLORS[d.coach] || '#888', display: 'inline-block' }} />
                  {d.coach}
                </span>,
                <span style={{ color: '#4b6fa8' }}>{d.date || '—'}</span>,
                d.offre ? <Pill color='#1e40af' bg='#dbeafe'>{d.offre}</Pill> : '—',
                <span style={{ fontWeight: 600, color: '#7F77DD' }}>{d.caEst > 0 ? fmtK(d.caEst) : '—'}</span>,
              ])}
            />
          </div>
        )}

        </>)}
      </div>
    </div>
  );
}